diff --git a/llvm/include/llvm/IR/PatternMatch.h b/llvm/include/llvm/IR/PatternMatch.h
index de24f4da336c2..8305f4dda7aff 100644
--- a/llvm/include/llvm/IR/PatternMatch.h
+++ b/llvm/include/llvm/IR/PatternMatch.h
@@ -510,6 +510,19 @@ inline api_pred_ty<is_maxsignedvalue> m_MaxSignedValue(const APInt *&V) {
   return V;
 }

+struct is_minsignedvalue {
+  bool isValue(const APInt &C) const { return C.isMinSignedValue(); }
+};
+/// Match an integer or vector with values having only the high bit set and
+/// all other bits cleared (0x80...).
+/// For vectors, this includes constants with undefined elements.
+inline cst_pred_ty<is_minsignedvalue> m_MinSignedValue() {
+  return cst_pred_ty<is_minsignedvalue>();
+}
+inline api_pred_ty<is_minsignedvalue> m_MinSignedValue(const APInt *&V) {
+  return V;
+}
+
 struct is_negative {
   bool isValue(const APInt &C) const { return C.isNegative(); }
 };
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index bffc887d93535..56f51bc67cfaa 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2154,6 +2154,15 @@ static Instruction *foldSelectICmpEq(SelectInst &SI, ICmpInst *ICI,
   if (Pred == ICmpInst::ICMP_NE)
     std::swap(TrueVal, FalseVal);

+  /// `A == MIN_INT ? MAX_INT : 0 - A` --> `ssub_sat 0, A`
+  if (match(CmpRHS, m_MinSignedValue()) && match(TrueVal, m_MaxSignedValue()) &&
+      match(FalseVal, m_Sub(m_ZeroInt(), m_Specific(CmpLHS)))) {
+    return IC.replaceInstUsesWith(
+        SI, IC.Builder.CreateBinaryIntrinsic(
+                Intrinsic::ssub_sat,
+                ConstantInt::getNullValue(CmpLHS->getType()), CmpLHS));
+  }
+
   if (Instruction *Res =
           foldSelectWithExtremeEqCond(CmpLHS, CmpRHS, TrueVal, FalseVal))
     return Res;

tests.test_body:
define <4 x i8> @fold_icmpne_to_ssub_sat_vec(<4 x i8> %a) {
  %cmp = icmp ne <4 x i8> %a, splat (i8 -128)
  %sub = sub <4 x i8> zeroinitializer, %a
  %sel = select <4 x i1> %cmp, <4 x i8> %sub, <4 x i8> splat (i8 127)
  ret <4 x i8> %sel
}

define <4 x i8> @fold_icmpeq_to_ssub_sat_vec(<4 x i8> %a) {
  %cmp = icmp eq <4 x i8> %a, splat (i8 -128)
  %sub = sub <4 x i8> zeroinitializer, %a
  %sel = select <4 x i1> %cmp, <4 x i8> splat (i8 127), <4 x i8> %sub
  ret <4 x i8> %sel
}

define i8 @fold_icmpne_to_ssub_sat(i8 %a) {
  %cmp = icmp ne i8 %a, -128
  %sub = sub i8 0, %a
  %sel = select i1 %cmp, i8 %sub, i8 127
  ret i8 %sel
}

define i8 @fold_icmpeq_to_ssub_sat(i8 %a) {
  %cmp = icmp eq i8 %a, -128
  %sub = sub i8 0, %a
  %sel = select i1 %cmp, i8 127, i8 %sub
  ret i8 %sel
}
